	private static List<String> predicateOrder(TupleExpr tupleExpr) {
		Join firstJoin = firstJoin(tupleExpr);
		assertNotNull(firstJoin, "expected at least one Join node after optimization");

		List<TupleExpr> joinArgs = new ArrayList<>();
		collectJoinArgs(firstJoin, joinArgs);

		List<String> order = new ArrayList<>();
		for (TupleExpr joinArg : joinArgs) {
			StatementPattern statementPattern = StatementPatternCollector.process(joinArg).get(0);
			order.add(statementPattern.getPredicateVar().getValue().stringValue());
		}
		return order;
	}

	private static Join firstJoin(TupleExpr tupleExpr) {
		AtomicReference<Join> found = new AtomicReference<>();
		tupleExpr.visit(new AbstractSimpleQueryModelVisitor<RuntimeException>() {
			@Override
			public void meet(Join node) {
				if (found.get() == null) {
					found.set(node);
				}
				super.meet(node);
			}
		});
		return found.get();
	}

	private static List<Join> allJoins(TupleExpr tupleExpr) {
		List<Join> joins = new ArrayList<>();
		tupleExpr.visit(new AbstractSimpleQueryModelVisitor<RuntimeException>() {
			@Override
			public void meet(Join node) {
				joins.add(node);
				super.meet(node);
			}
		});
		return joins;
	}

	private static List<TupleExpr> flattenedJoinArgs(TupleExpr tupleExpr) {
		Join rootJoin = firstJoin(tupleExpr);
		assertNotNull(rootJoin, "expected at least one Join node");
		List<TupleExpr> joinArgs = new ArrayList<>();
		collectJoinArgs(rootJoin, joinArgs);
		return joinArgs;
	}

	private static int indexOfJoinArg(List<TupleExpr> joinArgs, Predicate<TupleExpr> matcher) {
		for (int i = 0; i < joinArgs.size(); i++) {
			if (matcher.test(joinArgs.get(i))) {
				return i;
			}
		}
		return -1;
	}

	private static List<String> directStatementPredicateOrder(List<TupleExpr> joinArgs) {
		List<String> predicates = new ArrayList<>();
		for (TupleExpr joinArg : joinArgs) {
			if (joinArg instanceof StatementPattern) {
				Value value = ((StatementPattern) joinArg).getPredicateVar().getValue();
				if (value != null) {
					predicates.add(value.stringValue());
				}
			}
		}
		return predicates;
	}

	private static Join findJoinByPredicates(TupleExpr tupleExpr, Set<String> predicates) {
		AtomicReference<Join> found = new AtomicReference<>();
		tupleExpr.visit(new AbstractSimpleQueryModelVisitor<RuntimeException>() {
			@Override
			public void meet(Join node) {
				if (found.get() == null) {
					Set<String> nodePredicates = new TreeSet<>();
					for (StatementPattern statementPattern : StatementPatternCollector.process(node)) {
						Value predicateValue = statementPattern.getPredicateVar().getValue();
						if (predicateValue != null) {
							nodePredicates.add(predicateValue.stringValue());
						}
					}
					if (nodePredicates.equals(new TreeSet<>(predicates))) {
						found.set(node);
					}
				}
				super.meet(node);
			}
		});
		return found.get();
	}

	private static void collectJoinArgs(TupleExpr tupleExpr, List<TupleExpr> joinArgs) {
		if (tupleExpr instanceof Join) {
			Join join = (Join) tupleExpr;
			collectJoinArgs(join.getLeftArg(), joinArgs);
			collectJoinArgs(join.getRightArg(), joinArgs);
			return;
		}
		joinArgs.add(tupleExpr);
	}

	private static boolean isRightRecursive(TupleExpr tupleExpr) {
		if (!(tupleExpr instanceof Join)) {
			return true;
		}
		Join join = (Join) tupleExpr;
		if (join.getLeftArg() instanceof Join) {
			return false;
		}
		return isRightRecursive(join.getRightArg());
	}

	private static final class FixedStatistics extends EvaluationStatistics {
		private final Map<String, CardinalityEstimate> perPredicate;

		private FixedStatistics(Map<String, CardinalityEstimate> perPredicate) {
			this.perPredicate = perPredicate;
		}

		@Override
		public double getCardinality(TupleExpr expr) {
			return getCardinalityEstimate(expr).estimate;
		}

		@Override
		public CardinalityEstimate getCardinalityEstimate(TupleExpr expr) {
			if (expr instanceof StatementPattern) {
				Value predicateValue = ((StatementPattern) expr).getPredicateVar().getValue();
				if (predicateValue != null) {
					CardinalityEstimate estimate = perPredicate.get(predicateValue.stringValue());
					if (estimate != null) {
						return estimate;
					}
				}
			}
			return createCardinalityEstimate(100.0, 50.0, 200.0, 0.5, "fallback");
		}
	}

	private static final class PairAwareStatistics extends EvaluationStatistics {
		private final Map<String, CardinalityEstimate> perPredicate;
		private final Map<String, CardinalityEstimate> perPair;

		private PairAwareStatistics(Map<String, CardinalityEstimate> perPredicate,
				Map<String, CardinalityEstimate> perPair) {
			this.perPredicate = perPredicate;
			this.perPair = perPair;
		}

		@Override
		public boolean supportsJoinEstimation() {
			return true;
		}

		@Override
		public double getCardinality(TupleExpr expr) {
			return getCardinalityEstimate(expr).estimate;
		}

		@Override
		public CardinalityEstimate getCardinalityEstimate(TupleExpr expr) {
			if (expr instanceof StatementPattern) {
				Value predicateValue = ((StatementPattern) expr).getPredicateVar().getValue();
				if (predicateValue != null) {
					CardinalityEstimate estimate = perPredicate.get(predicateValue.stringValue());
					if (estimate != null) {
						return estimate;
					}
				}
			} else if (expr instanceof Join) {
				Join join = (Join) expr;
				String leftPredicate = firstPredicate(join.getLeftArg());
				String rightPredicate = firstPredicate(join.getRightArg());
				if (leftPredicate != null && rightPredicate != null) {
					CardinalityEstimate estimate = perPair.get(pairKey(leftPredicate, rightPredicate));
					if (estimate != null) {
						return estimate;
					}
				}
			}
			return createCardinalityEstimate(100.0, 50.0, 200.0, 0.5, "fallback");
		}

		private String firstPredicate(TupleExpr tupleExpr) {
			List<StatementPattern> patterns = StatementPatternCollector.process(tupleExpr);
			if (patterns.isEmpty()) {
				return null;
			}
			Value predicateValue = patterns.get(0).getPredicateVar().getValue();
			return predicateValue != null ? predicateValue.stringValue() : null;
		}
	}

	private static final class NoJoinEstimationStatistics extends EvaluationStatistics {
		private final Map<String, CardinalityEstimate> perPredicate;
		private int joinEstimateRequests;

		private NoJoinEstimationStatistics(Map<String, CardinalityEstimate> perPredicate) {
			this.perPredicate = perPredicate;
		}

		@Override
		public boolean supportsJoinEstimation() {
			return false;
		}

		@Override
		public double getCardinality(TupleExpr expr) {
			return getCardinalityEstimate(expr).estimate;
		}

		@Override
		public CardinalityEstimate getCardinalityEstimate(TupleExpr expr) {
			if (expr instanceof StatementPattern) {
				Value predicateValue = ((StatementPattern) expr).getPredicateVar().getValue();
				if (predicateValue != null) {
					CardinalityEstimate estimate = perPredicate.get(predicateValue.stringValue());
					if (estimate != null) {
						return estimate;
					}
				}
			} else if (expr instanceof Join) {
				joinEstimateRequests++;
				return createCardinalityEstimate(200.0, 100.0, 400.0, 0.5, "join-unsupported");
			}
			return createCardinalityEstimate(100.0, 50.0, 200.0, 0.5, "fallback");
		}

		private int joinEstimateRequests() {
			return joinEstimateRequests;
		}
	}

	private static final class CountingJoinEstimationStatistics extends EvaluationStatistics {
		private final Map<String, CardinalityEstimate> perPredicate;
		private int joinEstimateRequests;

		private CountingJoinEstimationStatistics(Map<String, CardinalityEstimate> perPredicate) {
			this.perPredicate = perPredicate;
		}

		@Override
		public boolean supportsJoinEstimation() {
			return true;
		}

		@Override
		public double getCardinality(TupleExpr expr) {
			return getCardinalityEstimate(expr).estimate;
		}

		@Override
		public CardinalityEstimate getCardinalityEstimate(TupleExpr expr) {
			if (expr instanceof StatementPattern) {
				Value predicateValue = ((StatementPattern) expr).getPredicateVar().getValue();
				if (predicateValue != null) {
					CardinalityEstimate estimate = perPredicate.get(predicateValue.stringValue());
					if (estimate != null) {
						return estimate;
					}
				}
			}

			if (expr instanceof Join) {
				joinEstimateRequests++;
				double estimate = 100.0 + joinEstimateRequests;
				return createCardinalityEstimate(estimate, estimate * 0.8, estimate * 1.2, 0.7, "counting-join");
			}

			return createCardinalityEstimate(100.0, 50.0, 200.0, 0.5, "fallback");
		}

		private int joinEstimateRequests() {
			return joinEstimateRequests;
		}
	}

	private static final class SlowCountingJoinEstimationStatistics extends EvaluationStatistics {
		private final Map<String, CardinalityEstimate> perPredicate;
		private final long joinEstimateDelayMs;
		private int joinEstimateRequests;

		private SlowCountingJoinEstimationStatistics(Map<String, CardinalityEstimate> perPredicate,
				long joinEstimateDelayMs) {
			this.perPredicate = perPredicate;
			this.joinEstimateDelayMs = Math.max(0L, joinEstimateDelayMs);
		}

		@Override
		public boolean supportsJoinEstimation() {
			return true;
		}

		@Override
		public double getCardinality(TupleExpr expr) {
			return getCardinalityEstimate(expr).estimate;
		}

		@Override
		public CardinalityEstimate getCardinalityEstimate(TupleExpr expr) {
			if (expr instanceof StatementPattern) {
				Value predicateValue = ((StatementPattern) expr).getPredicateVar().getValue();
				if (predicateValue != null) {
					CardinalityEstimate estimate = perPredicate.get(predicateValue.stringValue());
					if (estimate != null) {
						return estimate;
					}
				}
			}

			if (expr instanceof Join) {
				joinEstimateRequests++;
				if (joinEstimateDelayMs > 0L) {
					try {
						Thread.sleep(joinEstimateDelayMs);
					} catch (InterruptedException interruptedException) {
						Thread.currentThread().interrupt();
					}
				}
				double estimate = 100.0 + joinEstimateRequests;
				return createCardinalityEstimate(estimate, estimate * 0.8, estimate * 1.2, 0.7, "slow-counting-join");
			}

			return createCardinalityEstimate(100.0, 50.0, 200.0, 0.5, "fallback");
		}

		private int joinEstimateRequests() {
			return joinEstimateRequests;
		}
	}

